            //
            aOrbiterC = (aOrbiterC + aOrbiterK) + 5542262420102270800U;
            aOrbiterF = (aOrbiterF ^ aOrbiterC) ^ 4443990092241946068U;
            aOrbiterF = RotL64((aOrbiterF * 11059700631350046509U), 39U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterC) + 15703422927349887265U;
            aOrbiterE = (aOrbiterE ^ aOrbiterJ) ^ 7671986022871119819U;
            aOrbiterE = RotL64((aOrbiterE * 16153951439541699985U), 13U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterA) + 11311764283801325157U;
            aOrbiterI = (aOrbiterI ^ aOrbiterG) ^ 10228760154632821188U;
