            aOrbiterK = ((aWandererA + RotL64(aScatter, 13U)) + 10977979386099956540U) + aNonceWordD;
            aOrbiterB = (((aWandererE + RotL64(aIngress, 6U)) + 9536141786600348178U) + aOrbiterAssignSaltF[(((31U - aIndex) + 17U)) & S_SALT1]) + aNonceWordF;
            aOrbiterG = ((aWandererF + RotL64(aCross, 51U)) + 15612434280707409353U) + aNonceWordB;
            aOrbiterI = ((aWandererK + RotL64(aPrevious, 41U)) + 10277068920055235976U) + aOrbiterAssignSaltC[((aIndex + 25U)) & S_SALT1];
