            aOrbiterB = (aOrbiterB + aOrbiterD) + 15721686895944937820U;
            aOrbiterG = (aOrbiterG ^ aOrbiterB) ^ 16445804182691192730U;
            aOrbiterG = RotL64((aOrbiterG * 12653064133370436891U), 27U);
            //
            aOrbiterK = ((aOrbiterK + aOrbiterI) + 1331485182988442774U) + aOrbiterUpdateSaltD[((aIndex + 5U)) & S_SALT1];
            aOrbiterF = ((aOrbiterF ^ aOrbiterK) ^ 11543401819048348093U) ^ aOrbiterUpdateSaltA[((aIndex + 23U)) & S_SALT1];
            aOrbiterF = RotL64((aOrbiterF * 5470066089432380485U), 23U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterA) + 3526179693184132940U;
            aOrbiterB = (aOrbiterB ^ aOrbiterE) ^ 7118780070715708756U;
            aOrbiterB = RotL64((aOrbiterB * 13644990850289922459U), 53U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterH) + 8897215251073103532U;
            aOrbiterK = (aOrbiterK ^ aOrbiterC) ^ 14428770876983426413U;
            aOrbiterK = RotL64((aOrbiterK * 12064447790158547751U), 21U);
